@Beta
public abstract class AbstractFuture<V> implements ListenableFuture<V> {
@Override
  public boolean cancel(boolean mayInterruptIfRunning) {
    if (!sync.cancel()) {
      return false;
    }
    done();
    if (mayInterruptIfRunning) {
      interruptTask();
    }
    return true;
  }

protected void interruptTask() {
  }
}
